const source = $('Normalize Hero Reference Sheet').first().json;
const jobId = source.jobId || 'ft_' + Date.now();
const style = source.order?.illustrationStyle || 'storybook';
const fallbackStylePrompts = {
  disney: 'hand-drawn storybook animation aesthetic: expressive faces, clean outlines, vivid balanced colors, cinematic lighting, painterly background',
  watercolor: 'soft watercolor illustration, translucent washes, paper texture, gentle light',
  naive: 'naive folk storybook painting, simple bold shapes, warm handmade charm',
  toonflat: 'vintage flat cartoon storybook look, bold black outlines, flat warm colors, playful expressions',
  minibrick: 'brick-miniature toy diorama style: characters must be brick-built minifigures with cylindrical heads, C-shaped hands, blocky bodies, visible plastic studs and seams, glossy toy material, modular brick-built scenery',
  claymotion: 'handmade clay stop-motion storybook diorama, tactile sculpted clay textures, warm light',
  yarncraft: 'hand-knitted textile storybook diorama, visible yarn stitches and soft felt details',
  celcinema: 'cinematic cel-animation storybook look, clean color blocks, soft painterly background',
};
const makeStylePrompt = source.order?.illustrationStylePrompt || fallbackStylePrompts[style] || 'photorealistic cinematic book illustration, realistic people, natural light, print-ready composition';
const heroes = (source.order?.heroes || []).map((hero) => (hero.name || ('Hero ' + hero.n)) + ': ' + (hero.description || '')).join('; ');
const summary = source.text?.preview?.summary || source.text?.chapters?.[0]?.summary || 'Main characters in the opening scene with the important object.';
const location = source.order?.location || source.text?.bible?.location || '';
const artifact = source.order?.artifact || source.text?.bible?.artifact || '';
const bible = source.text?.bible || {};
const worldDirection = [
  bible.worldTitle ? 'World: ' + bible.worldTitle : '',
  bible.worldVisual ? 'World visual language: ' + bible.worldVisual : '',
  bible.worldMotifs ? 'World motifs to show through environment/props: ' + bible.worldMotifs : '',
  bible.worldConflict ? 'Emotional/environmental tension: ' + bible.worldConflict : '',
].filter(Boolean).join(' ');
const hasPortraitSheet = source.portraitSheet?.status === 'ready' && Boolean(source.portraitSheet?.contentBase64);
const referenceInstruction = hasPortraitSheet
  ? 'Use the attached generated character reference sheet as the primary canon for the heroes. It was created from the user photo references in the selected illustration style. Preserve the generated hero design consistently: facial identity cues, age impression, hair, glasses/accessories, outfit cues, proportions, and overall visual role. Do not go back to the original photos at this stage.'
  : 'No generated character reference sheet is attached; use the written hero descriptions consistently.';
const prompt = 'Create a square 1:1 book illustration. No text, no UI, no borders/watermarks.\n\n' +
  '[PRIORITY]\nSTYLE has highest priority; on any conflict follow STYLE.\nCHARACTER REFERENCE SHEET is the identity canon and must be used for the heroes.\nWORLD VISUAL controls palette, light, atmosphere, environment and props.\n\n' +
  '[CHARACTER REFERENCE SHEET]\n' + referenceInstruction + '\n\n' +
  '[WORLD VISUAL]\n' + (worldDirection || 'Use the story bible atmosphere and setting consistently.') + '\n\n' +
  '[STYLE]\n' + makeStylePrompt + '\n\n' +
  '[SCENE]\n' + summary + '\n\n' +
  '[LOCATION]\n' + location + '\n\n' +
  '[IMPORTANT OBJECT]\n' + artifact + '. The object must be visible and active in the scene.\n\n' +
  '[CHARACTERS]\n' + (heroes || 'the named main characters from the story') + '\n\n' +
  '[LOOK]\nIf STYLE is photorealistic or realistic, produce a photorealistic cinematic image based on the generated hero reference sheet, with realistic faces, natural skin texture, plausible lighting and lens depth. If STYLE is a materialized non-photo style (brick/clay/yarn/watercolor/cartoon), preserve the generated reference-sheet identity cues but render fully in that style.\n\n' +
  '[COMPOSITION]\nReadable silhouettes, clear focal hierarchy, foreground-midground-background separation, coherent anatomy, natural gestures, print-ready full-bleed square image.';
const parts = [{ text: prompt }];
if (hasPortraitSheet) {
  parts.push({ inlineData: { mimeType: source.portraitSheet.mimeType || 'image/png', data: source.portraitSheet.contentBase64 } });
}
const geminiImageRequest = { contents: [{ role: 'user', parts }], generationConfig: { responseModalities: ['IMAGE'], temperature: 0.45 } };
return [{ json: { ...source, jobId, status: 'visuals_generating', imagePrompt: prompt, geminiImageModel: 'gemini-2.5-flash-image', geminiImageRequest } }];

const source = $('Build Chapter 1 Image Prompt').first().json;
const response = $input.first().json;
const part = (response.candidates?.[0]?.content?.parts || []).find((candidatePart) => candidatePart.inlineData?.data);
if (!part) throw new Error('Gemini did not return an inline image for chapter 1');
const mimeType = part.inlineData.mimeType || 'image/png';
const ext = mimeType.includes('webp') ? 'webp' : mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
const fileName = `chapter-1.${ext}`;
const imageUrl = `/api/fairyteller/jobs/${source.jobId}/files/${fileName}`;
const absoluteImageUrl = `https://fairyteller.ru${imageUrl}`;
const image = { slot: 'chapter_1', status: 'ready', fileName, url: imageUrl, absoluteUrl: absoluteImageUrl, mimeType, bytes: Buffer.from(part.inlineData.data, 'base64').length, prompt: source.imagePrompt, provider: 'gemini', model: source.geminiImageModel || 'gemini-2.5-flash-image', referenceSheetUrl: source.portraitSheet?.url || null };
const preview = { ...(source.text?.preview || {}), imageStatus: 'ready', imageUrl, imageAbsoluteUrl: absoluteImageUrl };
const visuals = {
  style: source.order?.illustrationStyle || 'disney',
  portraitSheet: source.portraitSheet ? { ...source.portraitSheet, contentBase64: undefined } : null,
  portraits: (source.order?.heroes || []).map((hero) => ({
    hero: hero.n,
    name: hero.name || '',
    status: source.portraitSheet?.status === 'ready' ? 'reference_sheet_ready' : (hero.photoField ? 'photo_detected_no_sheet' : 'no_photo'),
    sourcePhotoField: hero.photoField || null,
    outputPath: source.portraitSheet?.url || null,
  })),
  imageJobs: [image, ...['cover', 'chapter_2', 'chapter_3', 'chapter_4', 'chapter_5'].map((slot) => ({ slot, status: 'queued_stub', outputPath: null }))],
};
return [{ json: { ...source, status: 'visuals_ready', text: { ...(source.text || {}), preview }, visuals, chapterOneFile: { fileName, contentType: mimeType, contentBase64: part.inlineData.data }, pipeline: { next: 'fairyteller_render_publish' } } }];

const payload = $('Normalize Chapter 1 Image').first().json;
delete payload.chapterOneFile.contentBase64;
return [{ json: payload }];

const item = $('Visuals Pipeline Input').first().json;
const input = $input.first();
const binary = input.binary || {};
const jobId = item.jobId || 'ft_' + Date.now();
const style = item.order?.illustrationStyle || 'disney';
const stylePrompt = item.order?.illustrationStylePrompt || 'photorealistic cinematic book character reference, natural skin, realistic face proportions, print-ready lighting';
const heroes = item.order?.heroes || [];
const parts = [];
let photoRefs = (item.photoRefs || item.order?._photoRefs || []).map((ref) => {
  const hero = heroes.find((candidate) => candidate.n === ref.hero) || { n: ref.hero };
  return { hero, key: ref.key, mimeType: ref.mimeType || hero.photoMime || 'image/jpeg', data: ref.data };
}).filter((ref) => ref.data);
if (photoRefs.length === 0) {
  photoRefs = [];
  for (const hero of heroes) {
    const key = hero.photoField;
    if (!key || !binary[key]) continue;
    const buffer = await this.helpers.getBinaryDataBuffer(0, key);
    photoRefs.push({ hero, key, mimeType: binary[key].mimeType || hero.photoMime || 'image/jpeg', data: buffer.toString('base64') });
  }
}
const heroDescriptions = heroes.map((hero) => 'Hero ' + hero.n + ': ' + (hero.name || 'unnamed') + '; ' + (hero.description || 'no description') + '; role/relation: ' + (hero.relation || 'not set') + '; photo reference: ' + (hero.photoField ? 'yes' : 'no')).join('\n');
const prompt = 'Generate an IMAGE, not a text answer. Create one canonical character reference image for a personalized book. The uploaded user photos are mandatory identity references for the matching heroes. Preserve recognizable identity cues: face shape, eyes and eyebrows, nose-to-lips ratio, hair color and length, complexion, age impression, beard or stubble, glasses, accessories and outfit cues. Render the hero as a fictional book character in the selected STYLE, while keeping likeness from the photo. STYLE from the original Make/frontend prompt: ' + stylePrompt + '. Arrange every listed hero clearly left to right in hero order, full-body or 3/4-body, neutral readable pose, clean background, no text, no labels, no logos, no watermarks. If only one hero is listed, create one clear canonical hero portrait/reference image. Heroes:\n' + (heroDescriptions || 'No heroes provided; create neutral main characters from the story descriptions.');
parts.push({ text: prompt });
for (const ref of photoRefs) {
  parts.push({ inlineData: { mimeType: ref.mimeType, data: ref.data } });
}
const geminiPortraitRequest = { contents: [{ role: 'user', parts }], generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.25 } };
return [{ json: { ...item, jobId, status: 'visuals_generating', portraitizer: { status: 'generating', style, stylePrompt, photoRefCount: photoRefs.length, heroCount: heroes.length }, geminiPortraitModel: 'gemini-2.5-flash-image', geminiPortraitRequest } }];

const source = $('Build Hero Reference Sheet').first().json;
let response = $input.first().json;
let part = (response.candidates?.[0]?.content?.parts || []).find((candidatePart) => candidatePart.inlineData?.data);
const photoRefCount = source.portraitizer?.photoRefCount || 0;
let responseText = (response.candidates?.[0]?.content?.parts || []).map((candidatePart) => candidatePart.text || '').join(' ').replace(/\s+/g, ' ').trim();

if (!part && photoRefCount > 0) {
  const originalParts = source.geminiPortraitRequest?.contents?.[0]?.parts || [];
  const imageParts = originalParts.filter((requestPart) => requestPart.inlineData?.data);
  const retryText = 'Generate an IMAGE only. Use the attached user photo as the mandatory identity reference for the hero. Create a single clean canonical character reference portrait for a personalized children book. Preserve recognizable facial likeness, age impression, hair, glasses/accessories and outfit cues. Use the selected style: ' + (source.order?.illustrationStylePrompt || source.order?.illustrationStyle || 'photorealistic book character') + '. No text, no labels, no logos, no watermark.';
  const retryRequest = {
    contents: [{ role: 'user', parts: [{ text: retryText }, ...imageParts] }],
    generationConfig: { responseModalities: ['TEXT', 'IMAGE'], temperature: 0.1 },
  };
  try {
    response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://generativelanguage.googleapis.com/v1beta/models/' + (source.geminiPortraitModel || 'gemini-2.5-flash-image') + ':generateContent',
      headers: { 'x-goog-api-key': $env.GEMINI_API_KEY, 'Content-Type': 'application/json' },
      body: retryRequest,
      json: true,
      timeout: 180000,
    });
    part = (response.candidates?.[0]?.content?.parts || []).find((candidatePart) => candidatePart.inlineData?.data);
    responseText = (response.candidates?.[0]?.content?.parts || []).map((candidatePart) => candidatePart.text || '').join(' ').replace(/\s+/g, ' ').trim();
  } catch (retryError) {
    responseText = retryError.message || responseText;
  }
}

const fallbackReason = responseText || response.promptFeedback?.blockReason || response.candidates?.[0]?.finishReason || 'Gemini did not return an inline image for the hero reference sheet';
if (!part && photoRefCount > 0) {
  const message = 'Не удалось создать визуальный референс героя по фото: ' + fallbackReason;
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: 'https://fairyteller.ru/api/fairyteller/jobs/' + source.jobId,
      headers: { Authorization: 'Bearer ' + $env.FAIRYTELLER_API_TOKEN, 'Content-Type': 'application/json' },
      body: { status: 'failed', stage: 'visuals', progress: 55, message, error: { message } },
      json: true,
    });
  } catch (patchError) {}
  throw new Error(message);
}
const transparentPngBase64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mP8/x8AAwMCAO+/p9sAAAAASUVORK5CYII=';
if (!part) {
  const mimeType = 'image/png';
  const fileName = 'hero-reference-sheet-skipped.png';
  const url = '/api/fairyteller/jobs/' + source.jobId + '/files/' + fileName;
  const portraitSheet = {
    status: 'skipped',
    reason: fallbackReason,
    fileName,
    url,
    absoluteUrl: 'https://fairyteller.ru' + url,
    mimeType,
    bytes: Buffer.from(transparentPngBase64, 'base64').length,
    provider: 'gemini',
    model: source.geminiPortraitModel || 'gemini-2.5-flash-image',
    style: source.order?.illustrationStyle || 'disney',
    photoRefCount,
    heroCount: source.portraitizer?.heroCount || 0,
    contentBase64: transparentPngBase64,
  };
  return [{ json: { ...source, portraitizer: { ...(source.portraitizer || {}), status: 'skipped', reason: portraitSheet.reason }, portraitSheet } }];
}
const mimeType = part.inlineData.mimeType || 'image/png';
const ext = mimeType.includes('webp') ? 'webp' : mimeType.includes('jpeg') || mimeType.includes('jpg') ? 'jpg' : 'png';
const fileName = 'hero-reference-sheet.' + ext;
